def scroll_all(client, collection, user_id):
    points, offset = [], None
    while True:
        result, next_offset = client.scroll(
            collection_name=collection,
            scroll_filter=Filter(must=[
                FieldCondition(key='user_id', match=MatchValue(value=user_id))
            ]),
            limit=100,
            offset=offset,
            with_payload=True,
            with_vectors=False,
        )
        points.extend(result)
        if next_offset is None:
            break
        offset = next_offset
    return [{'id': p.id, **p.payload} for p in points]

def bulk_set_expired(client, collection, user_id, cutoff_ts):
    old_ids, offset = [], None
    while True:
        result, next_offset = client.scroll(
            collection_name=collection,
            scroll_filter=Filter(must=[
                FieldCondition(key='user_id',    match=MatchValue(value=user_id)),
                FieldCondition(key='created_at', range=Range(lt=cutoff_ts)),
            ]),
            limit=100, offset=offset,
            with_payload=False, with_vectors=False,
        )
        old_ids.extend([p.id for p in result])
        if next_offset is None:
            break
        offset = next_offset
    if old_ids:
        import time
        client.set_payload(
            collection_name=collection,
            payload={'expired': True, 'expired_at': time.time()},
            points=old_ids,
        )
    return len(old_ids)
